"""Fresh task runner with full trajectory capture via Weave.

This module runs tasks with an LLM agent and captures the complete
trajectory (prompts, responses, tool calls, outputs) using Weave.

This is designed to generate rich behavioral data for reward modeling.
"""

import json
import os
from dataclasses import dataclass, field
from datetime import datetime
from pathlib import Path
from typing import Any

import weave
from anthropic import Anthropic
from openai import OpenAI


@dataclass
class ToolCall:
    """A single tool call in the trajectory."""
    name: str
    arguments: dict[str, Any]
    result: str
    timestamp: datetime = field(default_factory=datetime.now)
    error: str | None = None


@dataclass
class AgentStep:
    """A single step in the agent's trajectory."""
    step_number: int
    role: str  # "user", "assistant", "tool"
    content: str
    tool_calls: list[ToolCall] = field(default_factory=list)
    timestamp: datetime = field(default_factory=datetime.now)
    thinking: str = ""

    def to_dict(self) -> dict[str, Any]:
        return {
            "step_number": self.step_number,
            "role": self.role,
            "content": self.content[:2000] if self.content else "",
            "tool_calls": [
                {
                    "name": tc.name,
                    "arguments": tc.arguments,
                    "result": tc.result[:1000] if tc.result else "",
                    "error": tc.error,
                }
                for tc in self.tool_calls
            ],
            "timestamp": self.timestamp.isoformat(),
            "thinking": self.thinking[:500] if self.thinking else "",
        }


@dataclass
class FreshTrajectory:
    """Complete trajectory from a fresh task run."""
    task_name: str
    task_instruction: str
    agent_name: str
    model_name: str
    steps: list[AgentStep] = field(default_factory=list)
    started_at: datetime = field(default_factory=datetime.now)
    ended_at: datetime | None = None
    passed: bool = False
    final_code: str = ""
    test_output: str = ""
    error_message: str | None = None

    def to_dict(self) -> dict[str, Any]:
        return {
            "task_name": self.task_name,
            "task_instruction": self.task_instruction[:2000] if self.task_instruction else "",
            "agent_name": self.agent_name,
            "model_name": self.model_name,
            "steps": [s.to_dict() for s in self.steps],
            "started_at": self.started_at.isoformat(),
            "ended_at": self.ended_at.isoformat() if self.ended_at else None,
            "passed": self.passed,
            "final_code": self.final_code[:5000] if self.final_code else "",
            "test_output": self.test_output[:2000] if self.test_output else "",
            "error_message": self.error_message,
            "duration_sec": (self.ended_at - self.started_at).total_seconds() if self.ended_at else 0,
            "n_steps": len(self.steps),
        }

    def to_evaluation_text(self) -> str:
        """Convert trajectory to text format for LLM evaluation."""
        lines = [
            f"# Task: {self.task_name}",
            f"Agent: {self.agent_name} ({self.model_name})",
            f"Outcome: {'PASSED' if self.passed else 'FAILED'}",
            "",
            "## Task Instruction",
            self.task_instruction,
            "",
            "## Agent Trajectory",
        ]

        for step in self.steps:
            lines.append(f"\n### Step {step.step_number} ({step.role})")
            if step.thinking:
                lines.append(f"*Thinking:* {step.thinking[:500]}")
            lines.append(step.content[:1500])

            for tc in step.tool_calls:
                lines.append(f"\n**Tool: {tc.name}**")
                lines.append(f"Args: {json.dumps(tc.arguments, indent=2)[:500]}")
                lines.append(f"Result: {tc.result[:1000]}")
                if tc.error:
                    lines.append(f"Error: {tc.error}")

        if self.final_code:
            lines.append("\n## Final Code")
            lines.append("```python")
            lines.append(self.final_code[:3000])
            lines.append("```")

        if self.test_output:
            lines.append("\n## Test Output")
            lines.append(self.test_output[:1500])

        return "\n".join(lines)


AGENT_SYSTEM_PROMPT = """You are a skilled software engineer solving coding tasks. You have access to tools to write code and run tests.

When solving tasks:
1. First understand the requirements fully
2. Plan your approach before coding
3. Write clean, working code
4. Test your solution
5. Fix any errors you encounter

Available tools:
- write_file(path, content): Write content to a file
- read_file(path): Read content from a file  
- run_command(cmd): Run a shell command and get output
- submit(): Submit your solution when complete

Always write code to the /app directory.
When you're done, call submit() to finish."""


class FreshTaskRunner:
    """Runs tasks fresh and captures full trajectories with Weave."""

    def __init__(
        self,
        provider: str = "anthropic",
        model: str = "claude-sonnet-4-20250514",
        max_steps: int = 20,
    ):
        self.provider = provider
        self.model = model
        self.max_steps = max_steps

        if provider == "anthropic":
            self.client = Anthropic()
        elif provider == "openai":
            self.client = OpenAI()
        else:
            raise ValueError(f"Unsupported provider: {provider}")

        # Simulated file system for tool execution
        self._files: dict[str, str] = {}
        self._command_outputs: list[str] = []

    @weave.op()
    def run_task(
        self,
        task_name: str,
        task_instruction: str,
        test_command: str | None = None,
    ) -> FreshTrajectory:
        """Run a task and capture the full trajectory.

        Args:
            task_name: Name of the task
            task_instruction: The task instruction/prompt
            test_command: Optional command to verify solution

        Returns:
            FreshTrajectory with complete execution trace
        """
        trajectory = FreshTrajectory(
            task_name=task_name,
            task_instruction=task_instruction,
            agent_name=f"fresh-runner-{self.provider}",
            model_name=self.model,
        )

        # Reset file system
        self._files = {}
        self._command_outputs = []

        # Build messages
        messages = [
            {"role": "user", "content": task_instruction}
        ]

        step_num = 0
        submitted = False

        while step_num < self.max_steps and not submitted:
            step_num += 1

            # Call LLM
            response = self._call_llm(messages)

            # Parse response
            content = response.get("content", "")
            thinking = response.get("thinking", "")
            tool_calls_raw = response.get("tool_calls", [])

            # Create step
            step = AgentStep(
                step_number=step_num,
                role="assistant",
                content=content,
                thinking=thinking,
            )

            # Process tool calls
            tool_results = []
            for tc_raw in tool_calls_raw:
                tc_name = tc_raw.get("name", "")
                tc_args = tc_raw.get("arguments", {})

                # Execute tool
                result, error = self._execute_tool(tc_name, tc_args)

                tool_call = ToolCall(
                    name=tc_name,
                    arguments=tc_args,
                    result=result,
                    error=error,
                )
                step.tool_calls.append(tool_call)
                tool_results.append({
                    "tool": tc_name,
                    "result": result,
                    "error": error,
                })

                if tc_name == "submit":
                    submitted = True

            trajectory.steps.append(step)

            # Add assistant message
            messages.append({
                "role": "assistant",
                "content": content,
            })

            # Add tool results as user message if any
            if tool_results:
                result_text = "\n".join(
                    f"Tool '{r['tool']}': {r['error'] or r['result']}"
                    for r in tool_results
                )
                messages.append({
                    "role": "user",
                    "content": f"Tool results:\n{result_text}",
                })

                # Create tool result step
                tool_step = AgentStep(
                    step_number=step_num,
                    role="tool",
                    content=result_text,
                )
                trajectory.steps.append(tool_step)

        # Finalize trajectory
        trajectory.ended_at = datetime.now()

        # Get final code
        code_files = [
            (path, content) 
            for path, content in self._files.items() 
            if path.endswith('.py')
        ]
        if code_files:
            trajectory.final_code = code_files[0][1]

        # Run tests if command provided
        if test_command and trajectory.final_code:
            test_output, test_error = self._execute_tool(
                "run_command", 
                {"cmd": test_command}
            )
            trajectory.test_output = test_output
            trajectory.passed = test_error is None and "FAILED" not in test_output.upper()
            if test_error:
                trajectory.error_message = test_error
        else:
            # Mark as passed if we have code and submitted
            trajectory.passed = bool(trajectory.final_code and submitted)

        return trajectory

    @weave.op()
    def _call_llm(self, messages: list[dict]) -> dict:
        """Call the LLM and return parsed response."""
        if self.provider == "anthropic":
            # Define tools for Anthropic
            tools = [
                {
                    "name": "write_file",
                    "description": "Write content to a file",
                    "input_schema": {
                        "type": "object",
                        "properties": {
                            "path": {"type": "string", "description": "File path"},
                            "content": {"type": "string", "description": "File content"},
                        },
                        "required": ["path", "content"],
                    },
                },
                {
                    "name": "read_file",
                    "description": "Read content from a file",
                    "input_schema": {
                        "type": "object",
                        "properties": {
                            "path": {"type": "string", "description": "File path"},
                        },
                        "required": ["path"],
                    },
                },
                {
                    "name": "run_command",
                    "description": "Run a shell command",
                    "input_schema": {
                        "type": "object",
                        "properties": {
                            "cmd": {"type": "string", "description": "Command to run"},
                        },
                        "required": ["cmd"],
                    },
                },
                {
                    "name": "submit",
                    "description": "Submit your solution when complete",
                    "input_schema": {
                        "type": "object",
                        "properties": {},
                    },
                },
            ]

            response = self.client.messages.create(
                model=self.model,
                max_tokens=4096,
                system=AGENT_SYSTEM_PROMPT,
                tools=tools,
                messages=messages,
            )

            # Parse response
            content_parts = []
            tool_calls = []
            thinking = ""

            for block in response.content:
                if block.type == "text":
                    content_parts.append(block.text)
                elif block.type == "thinking":
                    thinking = block.thinking
                elif block.type == "tool_use":
                    tool_calls.append({
                        "name": block.name,
                        "arguments": block.input,
                    })

            return {
                "content": "\n".join(content_parts),
                "thinking": thinking,
                "tool_calls": tool_calls,
            }

        else:  # OpenAI
            # Define tools for OpenAI
            tools = [
                {
                    "type": "function",
                    "function": {
                        "name": "write_file",
                        "description": "Write content to a file",
                        "parameters": {
                            "type": "object",
                            "properties": {
                                "path": {"type": "string"},
                                "content": {"type": "string"},
                            },
                            "required": ["path", "content"],
                        },
                    },
                },
                {
                    "type": "function",
                    "function": {
                        "name": "read_file",
                        "description": "Read content from a file",
                        "parameters": {
                            "type": "object",
                            "properties": {
                                "path": {"type": "string"},
                            },
                            "required": ["path"],
                        },
                    },
                },
                {
                    "type": "function",
                    "function": {
                        "name": "run_command",
                        "description": "Run a shell command",
                        "parameters": {
                            "type": "object",
                            "properties": {
                                "cmd": {"type": "string"},
                            },
                            "required": ["cmd"],
                        },
                    },
                },
                {
                    "type": "function",
                    "function": {
                        "name": "submit",
                        "description": "Submit solution when complete",
                        "parameters": {"type": "object", "properties": {}},
                    },
                },
            ]

            response = self.client.chat.completions.create(
                model=self.model,
                max_tokens=4096,
                messages=[
                    {"role": "system", "content": AGENT_SYSTEM_PROMPT},
                    *messages,
                ],
                tools=tools,
            )

            msg = response.choices[0].message
            tool_calls = []

            if msg.tool_calls:
                for tc in msg.tool_calls:
                    tool_calls.append({
                        "name": tc.function.name,
                        "arguments": json.loads(tc.function.arguments) if tc.function.arguments else {},
                    })

            return {
                "content": msg.content or "",
                "thinking": "",
                "tool_calls": tool_calls,
            }

    def _execute_tool(self, name: str, args: dict) -> tuple[str, str | None]:
        """Execute a tool and return (result, error)."""
        try:
            if name == "write_file":
                path = args.get("path", "")
                content = args.get("content", "")
                self._files[path] = content
                return f"Wrote {len(content)} bytes to {path}", None

            elif name == "read_file":
                path = args.get("path", "")
                if path in self._files:
                    return self._files[path], None
                return "", f"File not found: {path}"

            elif name == "run_command":
                cmd = args.get("cmd", "")
                # Simulated command execution
                if "python" in cmd and "-c" in cmd:
                    # Simple Python execution simulation
                    return "Code executed successfully", None
                elif "pytest" in cmd or "test" in cmd:
                    # Simulated test execution
                    if self._files:
                        return "All tests passed", None
                    return "No files to test", "No code written yet"
                else:
                    return f"Simulated output for: {cmd}", None

            elif name == "submit":
                return "Solution submitted", None

            else:
                return "", f"Unknown tool: {name}"

        except Exception as e:
            return "", str(e)

    @weave.op()
    def run_task_batch(
        self,
        tasks: list[dict[str, str]],
    ) -> list[FreshTrajectory]:
        """Run multiple tasks and collect trajectories.

        Args:
            tasks: List of {"name": ..., "instruction": ..., "test_command": ...}

        Returns:
            List of FreshTrajectory objects
        """
        trajectories = []

        for task in tasks:
            trajectory = self.run_task(
                task_name=task.get("name", "unknown"),
                task_instruction=task.get("instruction", ""),
                test_command=task.get("test_command"),
            )
            trajectories.append(trajectory)

        return trajectories


def load_task_from_directory(task_path: Path) -> dict[str, str]:
    """Load a task from a task directory.

    Args:
        task_path: Path to task directory containing instruction.md and tests/

    Returns:
        Dict with name, instruction, test_command
    """
    task_name = task_path.name

    # Load instruction
    instruction_file = task_path / "instruction.md"
    if instruction_file.exists():
        instruction = instruction_file.read_text()
    else:
        # Try task.toml
        task_toml = task_path / "task.toml"
        if task_toml.exists():
            import toml
            data = toml.load(task_toml)
            instruction = data.get("instruction", f"Complete the task: {task_name}")
        else:
            instruction = f"Complete the task: {task_name}"

    # Determine test command
    test_script = task_path / "tests" / "test.sh"
    if test_script.exists():
        test_command = f"bash {test_script}"
    else:
        test_command = "pytest tests/ -v"

    return {
        "name": task_name,
        "instruction": instruction,
        "test_command": test_command,
    }
